// Semantic aliases — ported verbatim from aegis_icon()'s match() fallback in
// _shared/icons.php. These names resolve to an existing ICONS key so that
// pages using domain-language icon names (vault, incident, task…) render the
// intended glyph instead of falling back to 'dot'.
export const ICON_ALIASES = {
  'account':     'user',
  'system':      'info',
  'attestation': 'signature',
  'payment':     'dollar',
  'compliance':  'clock',
  'critical':    'alert-triangle',
  'warning':     'alert-circle',
  'document':    'file-text',
  'incident':    'alert-triangle',
  'vault':       'lock',
  'task':        'check-circle',
  'dollar-sign': 'dollar',
}
